239: func marshalRootModule(s *states.State, schemas *terraform.Schemas) (Module, error) {
240: 	var ret Module
241: 	var err error
242: 
243: 	ret.Address = ""
244: 	rs, err := marshalResources(s.RootModule().Resources, addrs.RootModuleInstance, schemas)
245: 	if err != nil {
246: 		return ret, err
247: 	}
248: 	ret.Resources = rs
249: 
250: 	// build a map of module -> set[child module addresses]
251: 	moduleChildSet := make(map[string]map[string]struct{})
252: 	for _, mod := range s.Modules {
253: 		if mod.Addr.IsRoot() {
254: 			continue
255: 		} else {
256: 			for childAddr := mod.Addr; !childAddr.IsRoot(); childAddr = childAddr.Parent() {
257: 				if _, ok := moduleChildSet[childAddr.Parent().String()]; !ok {
258: 					moduleChildSet[childAddr.Parent().String()] = map[string]struct{}{}
259: 				}
260: 				moduleChildSet[childAddr.Parent().String()][childAddr.String()] = struct{}{}
261: 			}
262: 		}
263: 	}
264: 
265: 	// transform the previous map into map of module -> [child module addresses]
266: 	moduleMap := make(map[string][]addrs.ModuleInstance)
267: 	for parent, children := range moduleChildSet {
268: 		for child := range children {
269: 			childModuleInstance, diags := addrs.ParseModuleInstanceStr(child)
270: 			if diags.HasErrors() {
271: 				return ret, diags.Err()
272: 			}
273: 			moduleMap[parent] = append(moduleMap[parent], childModuleInstance)
274: 		}
275: 	}
276: 
277: 	// use the state and module map to build up the module structure
278: 	ret.ChildModules, err = marshalModules(s, schemas, moduleMap[""], moduleMap)
279: 	return ret, err
280: }
