282: // marshalModules is an ungainly recursive function to build a module structure
283: // out of terraform state.
284: func marshalModules(
285: 	s *states.State,
286: 	schemas *terraform.Schemas,
287: 	modules []addrs.ModuleInstance,
288: 	moduleMap map[string][]addrs.ModuleInstance,
289: ) ([]Module, error) {
290: 	var ret []Module
291: 	for _, child := range modules {
292: 		// cm for child module, naming things is hard.
293: 		cm := Module{Address: child.String()}
294: 
